// Pull both ensures-foralls into the proof context so that z3 instantiates
// them on matching indices i (the original triggers are disjoint:
// post1_self_.page_array@[i] vs post2_self_.page_array@[i]).
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At `index`, every one of the 8 Page fields agrees between post1 and post2
// (each is pinned to pre_self_'s value, except `ref_count`, which is pinned
// to the input `ref_count` in both runs). Hand z3 the per-element fact.
assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);

// Pointwise across every valid index: post1.page_array@[i] == post2.page_array@[i].
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Index case: addr, state, is_io_page, rev_pointer, owning_container,
        // mappings, io_mappings all =~= pre_self_'s; ref_count =~= ref_count.
    } else {
        // Off-index case: both =~= pre_self_.page_array@[i] via the reasserted foralls.
    }
}

// Lift pointwise equality to sequence (view) equality of the page arrays.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
